        for row in self.board:
            for piece in row:
                if piece and not piece.is_king:
                    piece.promote()

    def check_winner(self):
        # Check for win/draw conditions
        return None


def main():
    game = CheckersGame()
    while True:
        game.print_board()
        print(f"Player {game.current_player}'s turn")
        from_pos = input("Enter move (e.g., '32 43'): ").split()
        to_pos = input("Enter move (e.g., '32 43'): ").split()

        if not all(from_pos) or not all(to_pos):
